scwin.f_openPgm = function (name) {
    if (name == "Find") {
        var strPath = "/ui/il/airout/aobk/ar_101_01_02b.xml";
        var param = {
            iogb: "I"
        };

        $c.win.openMenu("Customer Booking Search", strPath, "ar_101_01_02b.xml", param, { openAction: "exist" });
    } else if (name == "Master") {
        var strPath = "/ui/il/airinb/aibl/ar_202_01_01b.xml";
        var param = {
            kcomcd: scwin.hd_kcomcd
            , linkType: "MawbCreate"
            , avdt: ica_ed_ondt.getValue().trim()
            , dscd: ed_dscd.getValue().trim()
            , dsnm: txt_dsnm.getValue().trim()
            , fltno: ed_fltno.getValue().trim()
        };
        $c.win.openMenu("Import Master B/L", strPath, "ar_202_01_01b.xml", param, { openAction: "exist" });
    } else if (name == "House") {
        var strPath = "/ui/il/airinb/aibl/ar_203_01_01b.xml";
        var param = {
            blno: ed_cnd_ed_blno.getValue().trim()
            , kcomcd: scwin.hd_kcomcd
        };

        $c.win.openMenu("Import House B/L", strPath, "ar_203_01_01b.xml", param, { openAction: "exist" });
    }
};

